// Validate all required environment variables
const required = [
  'PULSE_PLANE_API_KEY',
  'PULSE_PLANE_BASE_URL',
  'PULSE_PLANE_WORKSPACE_SLUG',
  'PULSE_DAILY_QUEST_PROJECT_ID',
  'PULSE_STATE_TODO_ID',
  'PULSE_STATE_IN_PROGRESS_ID',
  'PULSE_STATE_DEFERRED_ID',
  'PULSE_STATE_DONE_ID',
  'PULSE_STATE_CANCELED_ID',
  'PULSE_LABEL_DAILY_ROUTINE_ID',
  'PULSE_DEEPSEEK_API_KEY',
  'PULSE_DEEPSEEK_BASE_URL',
  'PULSE_N8N_WEBHOOK_SECRET',
  'PULSE_USER_TIMEZONE'
];

const optional = [
  'PULSE_LOBEHUB_WEBHOOK_URL',
  'PULSE_LOBEHUB_API_KEY',
  'PULSE_DRY_RUN'
];

const results = [];
let allPassed = true;

for (const varName of required) {
  const value = $env[varName] || '';
  const passed = value.length > 0;
  if (!passed) allPassed = false;
  results.push({
    variable: varName,
    status: passed ? 'pass' : 'fail',
    required: true,
    message: passed ? 'Set' : 'Missing or empty'
  });
}

for (const varName of optional) {
  const value = $env[varName] || '';
  results.push({
    variable: varName,
    status: value.length > 0 ? 'pass' : 'skip',
    required: false,
    message: value.length > 0 ? 'Set' : 'Not configured (optional)'
  });
}

return [{
  json: {
    success: allPassed,
    data: { env_results: results },
    error: allPassed ? null : { code: 'ENV_VALIDATION_FAILED', message: 'One or more required variables are missing' },
    metadata: {
      step: 'env_validation',
      timestamp: new Date().toISOString(),
      items_processed: required.length + optional.length,
      items_failed: results.filter(r => r.status === 'fail').length
    }
  }
}];

const response = $input.first().json;
const statusCode = $input.first().json.$response?.statusCode || 200;
const isError = !!response.error || statusCode >= 400;

return [{
  json: {
    test: 'plane_api',
    status: isError ? 'fail' : 'pass',
    message: isError
      ? `Plane.so API error (HTTP ${statusCode}): ${response.message || response.error || 'Unknown error'}`
      : `Plane.so API connected successfully (${response.results?.length ?? 0} projects found)`
  }
}];

