const response = $input.first().json;
const isError = !!response.error;

let message;
if (isError) {
  message = `DeepSeek API error: ${response.error?.message || JSON.stringify(response.error)}`;
} else if (response.choices && response.choices.length > 0) {
  message = `DeepSeek API connected successfully (model: ${response.model || 'unknown'})`;
} else {
  message = 'DeepSeek API responded but returned unexpected format';
}

return [{
  json: {
    test: 'deepseek_api',
    status: isError ? 'fail' : 'pass',
    message
  }
}];

// LobeHub webhook connectivity test
// Only runs if PULSE_LOBEHUB_WEBHOOK_URL is configured
const webhookUrl = $env.PULSE_LOBEHUB_WEBHOOK_URL || '';

if (!webhookUrl) {
  return [{
    json: {
      test: 'lobehub_webhook',
      status: 'skip',
      message: 'LobeHub webhook URL not configured (optional)'
    }
  }];
}

// If configured, we pass the URL to the next HTTP node
return [{
  json: {
    webhook_url: webhookUrl,
    should_test: true
  }
}];

const response = $input.first().json;
const statusCode = $input.first().json.$response?.statusCode || 200;
const isError = statusCode >= 400;

return [{
  json: {
    test: 'lobehub_webhook',
    status: isError ? 'fail' : 'pass',
    message: isError
      ? `LobeHub webhook error (HTTP ${statusCode})`
      : 'LobeHub webhook reachable'
  }
}];

return [{
  json: {
    test: 'lobehub_webhook',
    status: 'skip',
    message: 'LobeHub webhook URL not configured (optional)'
  }
}];

// Aggregate all test results
const allItems = $input.all().map(i => i.json);

// Get env validation from the first workflow item
const envData = $('Code: Validate Environment Variables').first().json;
const envResults = envData.data.env_results;

// Collect connectivity test results
const connectivityTests = allItems;

// Build final report
const allTests = [
  ...envResults.map(r => ({
    category: 'environment',
    name: r.variable,
    status: r.status,
    message: r.message
  })),
  ...connectivityTests.map(r => ({
    category: 'connectivity',
    name: r.test,
    status: r.status,
    message: r.message
  }))
];

const failCount = allTests.filter(t => t.status === 'fail').length;
const passCount = allTests.filter(t => t.status === 'pass').length;
const skipCount = allTests.filter(t => t.status === 'skip').length;

const overallSuccess = failCount === 0;

return [{
  json: {
    success: overallSuccess,
    data: {
      summary: {
        total: allTests.length,
        passed: passCount,
        failed: failCount,
        skipped: skipCount
      },
      tests: allTests
    },
    error: overallSuccess
      ? null
      : { code: 'W0_VALIDATION_FAILED', message: `${failCount} test(s) failed` },
    metadata: {
      step: 'w0_environment_validator',
      timestamp: new Date().toISOString(),
      items_processed: allTests.length,
      items_failed: failCount
    }
  }
}];
